urlset:

{% for page in static_pages %}

    {{ site_url }}{{ page.url }}
    {% now "Y-m-d" %}
    {{ page.changefreq }}
    {{ page.priority }}

{% endfor %}


{% for post in blog_posts %}

    {{ site_url }}/blog/{{ post.slug }}/
    {{ post.updated_at|date:"Y-m-d" }}
    monthly
    0.8

{% endfor %}
